#!/bin/bash\n# Install script for sast-configuration skill\n\necho "Installing dependencies for sast-configuration..."\n\n# Update package list\necho "Updating package list..."\napt-get update -y\n\n# Install Python3 and pip\necho "Installing Python3 and pip..."\napt-get install -y python3 python3-pip\n\n# Install semgrep\necho "Installing semgrep..."\npip3 install semgrep\n\n# Install SonarQube scanner\necho "Installing SonarQube scanner..."\nwget -q https://binaries.sonarsource.com/Distribution/sonar-scanner-cli/sonar-scanner-cli-5.0.1.3006-linux.zip -O sonar-scanner.zip\nunzip -q sonar-scanner.zip -d /opt/\nmv /opt/sonar-scanner-* /opt/sonar-scanner\nln -sf /opt/sonar-scanner/bin/sonar-scanner /usr/local/bin/sonar-scanner\nrm sonar-scanner.zip\n\n# Install CodeQL CLI\necho "Installing CodeQL CLI..."\n# Note: CodeQL requires GitHub CLI first\nif ! command -v gh &> /dev/null; then\n    echo "Installing GitHub CLI..."\n    apt-get install -y gh\nfi\n\necho "✅ sast-configuration dependencies installed."\necho "Note: CodeQL CLI requires manual setup: gh extension install github/gh-codeql"\necho "      Then authenticate with: gh auth login"
